B.L8=s(["Live order queue with status filters","Search by order ID or customer","Fast preview and detailed order actions","Clear pricing and fulfillment visibility","Bottom navigation for merchant workflows","Operational layout tailored for kitchens and store counters"],t.s)
B.QJ=new A.ni("GrabGO Vendor App","Delivery Platform / Merchant Operations","Merchant app for handling live order queues, filtering incoming requests, and keeping store fulfillment organized in real time.","The GrabGO Vendor App gives restaurants and merchants a focused interface for processing orders from the platform. I designed it around queue visibility, fast state filtering, and quick action paths so vendors can preview orders, inspect details, and keep fulfillment moving without losing context. It is built to support real operational pressure at the point of sale.",B.Ll,B.Mg,"https://github.com/zakjnr999/GrabGo",B.L8,"Vendors need to process orders quickly, so the interface had to surface urgency, status, and action paths without clutter or unnecessary taps.","I used a state-filtered order workflow, action-first cards, and a clear information hierarchy so merchants can move from incoming order to fulfillment with minimal friction.")
B.LP=s(["assets/images/projects/citsa/Screenshot_1772346928.png","assets/images/projects/citsa/Screenshot_1772347432.png","assets/images/projects/citsa/Screenshot_1772347334.png","assets/images/projects/citsa/Screenshot_1772346854.png","assets/images/projects/citsa/Screenshot_1772346672.png","assets/images/projects/citsa/Screenshot_1772346656.png","assets/images/projects/citsa/Screenshot_1772346570.png","assets/images/projects/citsa/Screenshot_1772346509.png","assets/images/projects/citsa/Screenshot_1772346498.png","assets/images/projects/citsa/Screenshot_1772346455.png"],t.s)
